    text_input(
        &mut area,
        KeyEvent::new(KeyCode::Char('a'), KeyModifiers::CONTROL),
    );
    text_input(
        &mut area,
        KeyEvent::new(KeyCode::Char('k'), KeyModifiers::CONTROL),
    );
    assert_eq!(area.lines(), vec![""]);
}

