631	    /// Handle a mouse event. In list mode a left-click on a row both selects
632	    /// and opens it, matching the sidebar's click-to-activate behaviour;
633	    /// scroll wheel moves the cursor or scroll offset by one. Form modes
634	    /// ignore mouse input for now - their fields are keyboard-driven.
635	    fn handle_mouse(&mut self, m: MouseEvent) {
636	        match m.kind {
637	            MouseEventKind::Down(MouseButton::Left) => {
638	                if let Some(idx) = self.list_row_at(m.row) {
639	                    self.cursor = idx;
640	                    self.open_selected();
641	                    self.needs_draw = true;
642	                }
643	            }
644	            MouseEventKind::ScrollUp => {
645	                if matches!(self.content, Content::List(_) | Content::Doc(_)) {
646	                    self.move_by(-1);
647	                    self.needs_draw = true;
648	                }
649	            }
650	            MouseEventKind::ScrollDown => {
651	                if matches!(self.content, Content::List(_) | Content::Doc(_)) {
652	                    self.move_by(1);
653	                    self.needs_draw = true;
654	                }
655	            }
656	            _ => {}
657	        }
658	    }
659	
660	    /// The filtered list cursor's position in terminal row `row`, or `None`
661	    /// when the row falls on the header, the footer, or past the last visible
662	    /// entry. The body always starts at row 1 (right after the 1-row header)
663	    /// and is `viewport` rows tall.
664	    fn list_row_at(&self, row: u16) -> Option<usize> {
665	        if !matches!(self.content, Content::List(_)) {
666	            return None;
667	        }
668	        if row == 0 || row > self.viewport {
669	            return None;
670	        }
