        // convention; no other test in this crate touches `$TMUX`.
        unsafe {
            std::env::remove_var("TMUX");
        }
        assert_eq!(wrap_for_tmux("\x1b]52;c;ZA==\x07"), "\x1b]52;c;ZA==\x07");
        unsafe {
            std::env::set_var("TMUX", "/tmp/tmux-1000/default,123,0");
        }
