96	/// Try each candidate clipboard daemon command, in priority order, until one
97	/// accepts the payload. Returns `true` as soon as a child exits successfully.
98	///
99	/// Order: macOS first (`pbcopy`), then Wayland (`wl-copy`), then X11
100	/// (`xclip` then `xsel`). The `wl-copy` order before X11 matters because
101	/// systems that run both XWayland and Wayland natively often have both
102	/// `xclip` and `wl-copy` installed but only the latter actually reaches the
103	/// running compositor's clipboard.
104	fn copy_via_external_command(text: &str) -> bool {
105	    let candidates: &[(&str, &[&str])] = &[
106	        ("pbcopy", &[]),
107	        ("wl-copy", &[]),
108	        ("xclip", &["-selection", "clipboard"]),
109	        ("xsel", &["--clipboard", "--input"]),
110	    ];
111	    for &(cmd, args) in candidates {
112	        let Ok(mut child) = Command::new(cmd)
113	            .args(args)
114	            .stdin(Stdio::piped())
115	            .stdout(Stdio::null())
116	            .stderr(Stdio::null())
117	            .spawn()
118	        else {
119	            continue;
120	        };
121	        // Take stdin so dropping it closes the pipe and the child sees EOF;
122	        // without that close `wl-copy --foreground` (and friends) would
123	        // wait forever.
124	        if let Some(mut stdin) = child.stdin.take() {
125	            if stdin.write_all(text.as_bytes()).is_err() {
126	                let _ = child.kill();
127	                continue;
128	            }
129	        }
130	        if let Ok(status) = child.wait() {
131	            if status.success() {
132	                return true;
133	            }
134	        }
135	    }
136	    false
137	}
138	
139	/// Put `text` in the system clipboard. Tries the external clipboard daemon
140	/// commands first (the reliable path inside the cockpit, since Zellij eats
141	/// OSC 52 by default), then falls back to emitting OSC 52 on stdout for
142	/// the case where no clipboard daemon is reachable but the terminal can
143	/// forward OSC 52 to a different machine's clipboard.
144	pub(crate) fn copy_to_clipboard(text: &str) -> io::Result<()> {
145	    if copy_via_external_command(text) {
146	        return Ok(());
147	    }
148	    emit_osc52(text)
149	}
